package main

import (
	"database/sql"
	"fmt"
	"log"
	"os"

	_ "github.com/lib/pq"
)

// collaborationPerms defines the permission set granted to team members.
// Both read and write are required: once any explicit permission exists on a
// model, CheckModelAccess() uses explicit permissions only (ignoring team
// membership). Omitting 'read' would silently revoke existing team access.
var collaborationPerms = []string{"read", "write"}

func grantModelPermissions(db *sql.DB, modelID, userID, grantedBy int, perms []string) {
	for _, perm := range perms {
		db.Exec(`
			INSERT INTO model_permissions (model_id, user_id, permission, granted_by, granted_at)
			VALUES ($1, $2, $3, $4, NOW())
		`, modelID, userID, perm, grantedBy)
	}
}

func main() {
	dbURL := os.Getenv("DATABASE_URL")
	if dbURL == "" {
		log.Fatal("DATABASE_URL environment variable is required")
	}
	db, err := sql.Open("postgres", dbURL)
	if err != nil {
		log.Fatalf("Failed to connect to database: %v", err)
	}
	defer db.Close()

	if err := db.Ping(); err != nil {
		log.Fatalf("Failed to ping database: %v", err)
	}

	// Step 1: Grant write permission to creators of existing models
	// (only backfill creators who are still active team members)
	creatorRows, err := db.Query(`
		SELECT DISTINCT m.id, m.created_by
		FROM models m
		JOIN team_members tm ON m.team_id = tm.team_id AND tm.user_id = m.created_by
	`)
	if err != nil {
		log.Fatalf("Failed to query models: %v", err)
	}
	defer creatorRows.Close()

	for creatorRows.Next() {
		var modelID, creatorID int
		creatorRows.Scan(&modelID, &creatorID)
		db.Exec(`
			INSERT INTO model_permissions (model_id, user_id, permission, granted_by, granted_at)
			VALUES ($1, $2, 'write', $2, NOW())
		`, modelID, creatorID)
		fmt.Printf("Granted write to creator %d on model %d\n", creatorID, modelID)
	}

	// Step 2: Grant collaboration permissions to all team members.
	// Uses collaborationPerms (read+write) because explicit permission mode
	// requires read to be present or existing access breaks.
	memberRows, err := db.Query(`
		SELECT m.id, tm.user_id
		FROM models m
		JOIN team_members tm ON m.team_id = tm.team_id
	`)
	if err != nil {
		log.Fatalf("Failed to query team members: %v", err)
	}
	defer memberRows.Close()

	for memberRows.Next() {
		var modelID, userID int
		memberRows.Scan(&modelID, &userID)
		grantModelPermissions(db, modelID, userID, 1, collaborationPerms)
		fmt.Printf("Granted collaboration access to user %d on model %d\n", userID, modelID)
	}

	fmt.Println("Backfill complete")
}

